    c = str(c).strip() if c else ""
    mapping = {
        '数院': '数学科学学院', '物院': '物理与天文学院', '物天': '物理与天文学院',
        '计院': '计算机科学与技术学院', '机动': '机械与动力工程学院', '生科院': '生命科学技术学院',
        '电院': '电子信息与电气工程学院', '外国语学': '外国语学院', '外国语': '外国语学院',
        '材料': '材料科学与工程学院'
    }
    return mapping.get(c, c)

def normalize_degree(d):
    d = str(d).strip() if d else ""
    if '博' in d: return '博士'
    if '硕' in d: return '硕士'
    if '本' in d: return '本科'
    return d

def normalize_province(p):
    p = str(p).strip() if p else ""
    if '回族自治区' in p: p = p.replace('回族自治区', '')
    if '维吾尔自治区' in p: p = p.replace('维吾尔自治区', '')
    if '壮族自治区' in p: p = p.replace('壮族自治区', '')
    if '自治区' in p: p = p.replace('自治区', '')
    if p.endswith('省') or p.endswith('市'): p = p[:-1]
    return p

def normalize_nation(n):
    n = str(n).strip() if n else ""
    if n.endswith('族'): n = n[:-1]
    return n

def normalize_money(m):
    m = str(m).replace('元', '').strip()
    try:
        return int(float(m))
    except:
        return m

wb = load_workbook('context/EXCEL汇总表整理.xlsx')
ws = wb['Sheet1']
